import{_ as t,c as a,o as i,aa as e}from"./chunks/framework.DZPhBpRd.js";const c=JSON.parse('{"title":"API 响应模型的设计哲学与范式","description":"梳理成功与失败响应的设计差异背后的逻辑，以及主流 API 的实践与取舍","frontmatter":{"title":"API 响应模型的设计哲学与范式","description":"梳理成功与失败响应的设计差异背后的逻辑，以及主流 API 的实践与取舍","date":"2026-03-08T15:30:00.000Z","tags":["API设计","后端"]},"headers":[],"relativePath":"posts/API 响应模型的设计哲学与范式.md","filePath":"posts/API 响应模型的设计哲学与范式.md","lastUpdated":1772956010000}'),d={name:"posts/API 响应模型的设计哲学与范式.md"};function o(n,s,l,h,r,p){return i(),a("div",null,[...s[0]||(s[0]=[e(`<blockquote><p>成功只有一个结果，失败却有多种原因</p></blockquote><p>以前我对 API 响应的理解是：无论成功还是失败，都应该用统一的模型包装，例如 <code>{ code, message, data }</code>，通过 <code>code</code> 判断成功与否，<code>data</code> 承载结果。以前公司的设计也是如此——所有接口都返回带包装的格式，成功和失败共用一套信封。</p><p>经过一轮思考和对比主流实践后，我的结论是：<strong>成功和失败的信息结构应当不同</strong>。成功时，依靠 HTTP 状态码即可表达「请求成功」，Body 直接返回资源；失败时，则需要用结构化的 <code>code</code> 和 <code>message</code> 同时告诉<strong>程序</strong>（为何失败、如何分支）和<strong>人</strong>（如何展示、如何解释）。信封式的统一包装并非必须，甚至会带来冗余。</p><p>下文展开这种设计背后的逻辑与取舍。</p><h2 id="一、两种设计路线" tabindex="-1">一、两种设计路线 <a class="header-anchor" href="#一、两种设计路线" aria-label="Permalink to &quot;一、两种设计路线&quot;">​</a></h2><p>API 响应模型本质要回答三个问题：客户端如何知道请求成功还是失败？成功时数据在哪？失败时如何得知原因？</p><p>由此衍生出两条路线：</p><table tabindex="0"><thead><tr><th>路线</th><th>思路</th><th>成功</th><th>失败</th></tr></thead><tbody><tr><td><strong>用 HTTP 表达语义</strong></td><td>状态码负责成功/失败，Body 负责业务内容</td><td>200 + 直接返回资源</td><td>4xx/5xx + 错误描述</td></tr><tr><td><strong>用 Body 表达语义</strong></td><td>不依赖状态码</td><td><code>{ success: true, data }</code></td><td><code>{ success: false, error }</code></td></tr></tbody></table><p>主流实践（Stripe、GitHub、微信、支付宝）多采用前者：<strong>让 HTTP 状态码承担「成功/失败」的语义，Body 专注承载业务数据或错误详情</strong>。</p><h2 id="二、成功响应-为什么直接返回资源" tabindex="-1">二、成功响应：为什么直接返回资源？ <a class="header-anchor" href="#二、成功响应-为什么直接返回资源" aria-label="Permalink to &quot;二、成功响应：为什么直接返回资源？&quot;">​</a></h2><p><strong>设计理念</strong>：成功时，客户端要的就是资源本身。</p><ul><li>资源已包含所需信息，无需再包一层 <code>{ data: resource }</code></li><li>解析更直接：<code>const user = response</code> 而不是 <code>const user = response.data</code></li><li>减少冗余：200 已表示成功，<code>success: true</code> 显得多余</li></ul><p>因此常见做法是：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /users/123 → 200</span></span>
<span class="line"><span>{ &quot;id&quot;: &quot;123&quot;, &quot;display_name&quot;: &quot;张三&quot;, ... }</span></span></code></pre></div><p>而不是：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;success&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;data&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;123&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } }</span></span></code></pre></div><h2 id="三、失败响应-为什么需要-code-和-message" tabindex="-1">三、失败响应：为什么需要 code 和 message？ <a class="header-anchor" href="#三、失败响应-为什么需要-code-和-message" aria-label="Permalink to &quot;三、失败响应：为什么需要 code 和 message？&quot;">​</a></h2><p><strong>设计理念</strong>：失败时，信息是不对称的——原因多样，需要结构化表达。</p><h3 id="http-状态码能表达的" tabindex="-1">HTTP 状态码能表达的 <a class="header-anchor" href="#http-状态码能表达的" aria-label="Permalink to &quot;HTTP 状态码能表达的&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状态码</th><th>含义</th></tr></thead><tbody><tr><td>400</td><td>请求有问题</td></tr><tr><td>401</td><td>未认证</td></tr><tr><td>403</td><td>无权限</td></tr><tr><td>404</td><td>资源不存在</td></tr><tr><td>422</td><td>校验失败</td></tr><tr><td>429</td><td>请求过多</td></tr><tr><td>500</td><td>服务端错误</td></tr></tbody></table><p>状态码只告诉你<strong>错误大类</strong>，不告诉你<strong>具体是哪一种</strong>。同为 400，可能是手机号格式错误、验证码错误、验证码过期——客户端无法区分。</p><h3 id="code-和-message-各司其职" tabindex="-1">code 和 message 各司其职 <a class="header-anchor" href="#code-和-message-各司其职" aria-label="Permalink to &quot;code 和 message 各司其职&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>受众</th><th>作用</th></tr></thead><tbody><tr><td><code>code</code></td><td>程序</td><td>机器可读，用于分支逻辑、重试策略、监控统计</td></tr><tr><td><code>message</code></td><td>用户</td><td>人类可读，用于 Toast/Alert 直接展示</td></tr></tbody></table><p>示例：</p><div class="language-swift vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">swift</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> error.code </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;INVALID_CODE&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    showAlert</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;验证码错误，请重新输入&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> error.code </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;CODE_EXPIRED&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    showAlert</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;验证码已过期，请重新获取&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="小结-成功与失败的不对称性" tabindex="-1">小结：成功与失败的不对称性 <a class="header-anchor" href="#小结-成功与失败的不对称性" aria-label="Permalink to &quot;小结：成功与失败的不对称性&quot;">​</a></h3><ul><li><strong>成功</strong>：结果单一，<strong>靠 HTTP 状态码（200）表达成功</strong>，Body 直接返回资源即可。</li><li><strong>失败</strong>：原因多样，<strong>需要同时告诉人和机器</strong>——<code>code</code> 给程序做分支与监控，<code>message</code> 给人展示，必要时用 <code>details</code> 给出校验明细。</li></ul><p>这种不对称性，正是成功和失败设计哲学不同的根源。</p><h2 id="四、主流实践一览" tabindex="-1">四、主流实践一览 <a class="header-anchor" href="#四、主流实践一览" aria-label="Permalink to &quot;四、主流实践一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>服务</th><th>成功</th><th>错误</th></tr></thead><tbody><tr><td>Stripe</td><td>直接返回对象</td><td><code>{ &quot;error&quot;: { &quot;code&quot;: &quot;...&quot;, &quot;message&quot;: &quot;...&quot; } }</code></td></tr><tr><td>GitHub</td><td>直接返回对象/数组</td><td><code>{ &quot;message&quot;: &quot;...&quot;, &quot;errors&quot;: [...] }</code></td></tr><tr><td>微信开放平台</td><td>直接返回业务字段</td><td><code>{ &quot;errcode&quot;: 40001, &quot;errmsg&quot;: &quot;...&quot; }</code></td></tr><tr><td>支付宝</td><td>直接返回业务字段</td><td><code>{ &quot;code&quot;: &quot;10000&quot;, &quot;msg&quot;: &quot;...&quot;, &quot;sub_code&quot;: &quot;...&quot; }</code></td></tr></tbody></table><p>共同点：<strong>成功时直接返回资源，失败时用简单 JSON 表达 code/message，不套多层 envelope</strong>。</p><h2 id="五、推荐的错误结构" tabindex="-1">五、推荐的错误结构 <a class="header-anchor" href="#五、推荐的错误结构" aria-label="Permalink to &quot;五、推荐的错误结构&quot;">​</a></h2><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;code&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;INVALID_CODE&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;message&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;验证码错误或已过期&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;details&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;field&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;code&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;message&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;必须是 6 位数字&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ul><li><code>code</code>：业务错误码，用于程序判断。</li><li><code>message</code>：用户可见说明。</li><li><code>details</code>：可选，校验失败时逐字段说明。</li></ul><h2 id="六、设计原则小结" tabindex="-1">六、设计原则小结 <a class="header-anchor" href="#六、设计原则小结" aria-label="Permalink to &quot;六、设计原则小结&quot;">​</a></h2><ol><li><strong>HTTP 能表达的交给 HTTP</strong>：状态码表示 success/fail，Body 表示业务内容。</li><li><strong>成功时 Body 就是你要的</strong>：不必再包一层 <code>data</code>。</li><li><strong>失败时需要结构化</strong>：<code>code</code> + <code>message</code>，必要时加 <code>details</code>。</li><li><strong>简单优于复杂</strong>：够用即可，不追求 RFC 7807 等完整规范。</li><li><strong>保持一致性</strong>：成功和失败都用统一格式，减少客户端分支逻辑。</li></ol>`,36)])])}const g=t(d,[["render",o]]);export{c as __pageData,g as default};
